// Sidebar.js
import React, { useState } from 'react';
import './Sidebar.css';

const Sidebar = ({ onSelectionChange }) => {
    // Keep local state for the active menu option
    const [activeId, setActiveId] = useState('stats'); // default active

    const handleClick = (id) => {
        setActiveId(id);
        onSelectionChange && onSelectionChange(id);
    };

    return (
        <nav className="sidebar">
            <div className="sidebar-header">Billy</div>
            <ul className="menu">
                <li
                    className={`menu-item ${activeId === 'stats' ? 'active' : ''}`}
                    onClick={() => handleClick('stats')}
                >
                    Stats
                </li>
                <li
                    className={`menu-item ${activeId === 'wrapped' ? 'active' : ''}`}
                    onClick={() => handleClick('wrapped')}
                >
                    Wrapped
                </li>
                <li
                    className={`menu-item ${activeId === 'to-add' ? 'active' : ''}`}
                    onClick={() => handleClick('to-add')}
                >
                    To add
                </li>
                <li
                    className={`menu-item ${activeId === 'to-remove' ? 'active' : ''}`}
                    onClick={() => handleClick('to-remove')}
                >
                    To remove
                </li>
                <li
                    className={`menu-item ${activeId === 'to-reprice' ? 'active' : ''}`}
                    onClick={() => handleClick('to-reprice')}
                >
                    To reprice
                </li>
                <li
                    className={`menu-item ${activeId === 'to-promote' ? 'active' : ''}`}
                    onClick={() => handleClick('to-promote')}
                >
                    To promote
                </li>
            </ul>
            <div className="sidebar-footer">Footer Content</div>
        </nav>
    );
};

export default Sidebar;
